class Box {
 int width, height;
public:
 Box(int w, int h) : width(w), height(h) {}
 void display() { cout << width << "x" << height; }
};

void modify(Box b) { // Pass by value - creates copy
 b.width = 20; // Modifies copy only
 b.display(); // Shows 20x10
}

int main() {
 Box b(10, 10);
 modify(b); // Copy constructor invoked
 b.display(); // Still shows 10x10 - original unchanged
 return 0;
}

class Box {
 int width, height;
public:
 Box(int w, int h) : width(w), height(h) {}
 void display() { cout << width << "x" << height; }
};

void modify(Box& b) { // Pass by reference - no copy
 b.width = 20; // Modifies original object
 b.display(); // Shows 20x10
}

int main() {
 Box b(10, 10);
 modify(b); // No copy made
 b.display(); // Shows 20x10 - original modified
 return 0;
}

class Box {
 int width, height;
public:
 Box(int w, int h) : width(w), height(h) {}
 void display() { cout << width << "x" << height; }
 int getArea() const { // const member function
 return width * height;
 }
};

void displayArea(const Box& b) { // const reference
 // b.width = 20; // ERROR - cannot modify
 cout << b.getArea(); // Can only read
}

int main() {
 Box b(10, 20);
 displayArea(b); // Efficient - no copy, no modification risk
 return 0;
}

class Box {
 int width, height;
public:
 Box(int w, int h) : width(w), height(h) {}
 void display() { cout << width << "x" << height; }
};

void modify(Box* ptr) { // Pass by pointer
 if (ptr == nullptr) return; // NULL check
 ptr->width = 30; // Modify through pointer
 ptr->display();
}

int main() {
 Box b(10, 10);
 modify(&b); // Pass address
 b.display(); // Shows 30x10

 Box* p = nullptr;
 modify(p); // Safe - NULL checked
 return 0;
}

class Base {
public:
 int baseData;
 Base(int b) : baseData(b) {}
 virtual void show() { cout << "Base: " << baseData; }
};

class Derived : public Base {
public:
 int derivedData;
 Derived(int b, int d) : Base(b), derivedData(d) {}
 void show() override { 
 cout << "Base: " << baseData << ", Derived: " << derivedData; 
 }
};

void display(Base b) { // Slicing happens here!
 b.show(); // Calls Base::show()
}

int main() {
 Derived obj(10, 20);
 display(obj); // Object sliced!
 // derivedData lost
 return 0;
}

class Base {
public:
 int baseData;
 Base(int b) : baseData(b) {}
 virtual void show() { cout << "Base: " << baseData; }
 virtual ~Base() {}
};

class Derived : public Base {
public:
 int derivedData;
 Derived(int b, int d) : Base(b), derivedData(d) {}
 void show() override { 
 cout << "Base: " << baseData << ", Derived: " << derivedData; 
 }
};

// Solution 1: Pass by pointer
void displayPtr(Base* ptr) {
 ptr->show(); // Calls Derived::show()
}

// Solution 2: Pass by reference
void displayRef(Base& ref) {
 ref.show(); // Calls Derived::show()
}

int main() {
 Derived obj(10, 20);
 displayPtr(&obj); // No slicing - polymorphism works
 displayRef(obj); // No slicing - polymorphism works
 return 0;
}
